INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VSG_2017_consolidated', 'VSG', 2017, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 1, 'Công ty tiếp tục bị lỗ 50.327.941.689 VND và khoản lỗ lũy kế đến ngày 31 tháng 12 năm 2017 là 469.559.865.261 VND. Ngoài ra, tại ngày 31 tháng 12 năm 2017 các khoản nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn của Công ty là 522.763.369.563 VND.'),
('VSF_2025_consolidated', 'VSF', 2025, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM - Thành viên Hãng Kiểm toán Quốc tế INPACT', 'unqualified', 0, NULL),
('VSG_2016_consolidated', 'VSG', 2016, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 1, 'Công ty tiếp tục bị lỗ 40,143,956,219 VND trong năm 2016, lỗ lũy kế 419,231,923,572 VND. Nợ ngắn hạn vượt quá tài sản ngắn hạn 511,392,257,412 VND. Công ty đang làm việc với ngân hàng để có kế hoạch trả nợ phù hợp.'),
('VSG_2015_consolidated', 'VSG', 2015, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 1, 'Công ty tiếp tục bị lỗ 91.725.417.358 VND và khoản lỗ lũy kế 379.087.967.353 VND. Nợ ngắn hạn vượt quá tài sản ngắn hạn 508.996.977.891 VND, nghi ngờ khả năng hoạt động liên tục.'),
('VSF_2023_consolidated', 'VSF', 2023, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 0, NULL),
('VSF_2024_consolidated', 'VSF', 2024, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 1, 'Tổng Công ty đang chịu khoản lỗ lũy kế đến 31/12/2024 là 2.641.548.688.028 VND, dẫn đến thâm hụt vốn chủ sở hữu. Khả năng tiếp tục hoạt động phụ thuộc vào việc các tổ chức tín dụng cung cấp và duy trì đủ hạn mức tín dụng. Công ty đã triển khai Đề án tái cơ cấu được Ủy ban quản lý vốn Nhà nước phê duyệt theo Quyết định số 2902/UBQLV-NN ngày 29/12/2023.'),
('VSF_2023_parent', 'VSF', 2023, 'parent', 'CPA VIETNAM', 'unqualified', 1, 'Tổng Công ty đang chịu lỗ lũy kế 2.645.851.822.319 VND và thâm hụt vốn chủ sở hữu, dẫn đến phụ thuộc vào tín dụng ngân hàng để thanh toán nợ. Ban Tổng Giám đốc đã triển khai kế hoạch tái cơ cấu và tin tưởng hoạt động liên tục.'),
('VSF_2022_consolidated', 'VSF', 2022, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 0, NULL),
('VSF_2022_parent', 'VSF', 2022, 'parent', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 0, NULL),
('VTM_2018_consolidated', 'VTM', 2018, 'consolidated', 'Công Ty TNHH PKF Việt Nam', 'unqualified', 0, NULL),
('WSB_2015_parent', 'WSB', 2015, 'parent', 'PricewaterhouseCoopers Vietnam', 'qualified', 0, NULL),
('XPH_2016_consolidated', 'XPH', 2016, 'consolidated', 'CÔNG TY TNHH KIỂM TOÁN VÀ ĐỊNH GIÁ VIỆT NAM', 'unqualified', 0, NULL),
('VTJ_2021_parent', 'VTJ', 2021, 'parent', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'unqualified', 0, NULL),
('VTD_2024_consolidated', 'VTD', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VSI_2022_parent', 'VSI', 2022, 'parent', 'Công ty TNHH Dịch vụ Tư vấn Tài chính Kế toán và Kiểm toán Phía Nam (AASCS)', 'unqualified', 0, NULL),
('VSM_2022_parent', 'VSM', 2022, 'parent', 'Công ty TNHH Kiểm toán TTP', 'unqualified', 0, NULL),
('VSF_2020_consolidated', 'VSF', 2020, 'consolidated', '', 'unqualified', 1, 'Công ty liên tục lỗ trong năm 2019 và 2020, lợi nhuận sau thuế âm, cho thấy nguy cơ về hoạt động liên tục.'),
('VSF_2019_consolidated', 'VSF', 2019, 'consolidated', 'KPMG', 'qualified', 1, NULL),
('VSF_2020_parent', 'VSF', 2020, 'parent', 'KPMG Việt Nam', 'unqualified', 1, 'Tổng Công ty có lỗ lũy kế lớn, nợ ngắn hạn vượt tài sản ngắn hạn 14,319 triệu VND, và các khoản vay đáng kể cần tái tài trợ. Giá trị giả định hoạt động liên tục phụ thuộc vào khả năng tạo đủ dòng tiền và duy trì hạn mức tín dụng từ các tổ chức tín dụng.'),
('VSF_2019_parent', 'VSF', 2019, 'parent', 'KPMG Việt Nam', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2019, nợ ngắn hạn đã vượt quá tài sản ngắn hạn 13.509 triệu VND và Tổng Công ty có các khoản vay đáng kể cần tái tài trợ trong vòng 12 tháng kế tiếp. Tuy nhiên, Ban Tổng Giám đốc tin rằng Tổng Công ty có thể tạo ra đủ dòng tiền từ hoạt động kinh doanh và tiếp tục sử dụng hạn mức tín dụng từ các tổ chức tín dụng để thanh toán các khoản nợ đến hạn và duy trì hoạt động liên tục.');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VSF_2021_parent', 'VSF', 2021, 'parent', 'Chi nhánh Công ty TNHH KPMG tại Thành phố Hồ Chí Minh', 'unqualified', 1, 'Nợ ngắn hạn đã vượt quá tài sản ngắn hạn là 101.790 triệu VND. Lỗ thuần sau thuế trong năm là 352.088 triệu VND, lưu chuyển tiền thuần từ hoạt động kinh doanh âm 273.977 triệu VND. Giá trị giả định hoạt động liên tục phụ thuộc vào việc các tổ chức tín dụng cung cấp và duy trì đủ hạn mức tín dụng.'),
