('VPW_2017_consolidated', 'VPW', 2017, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 1, 'Kiểm toán viên không thể thu thập đầy đủ bằng chứng kiểm toán về tính chính xác của giá trị tài sản cố định - Nhà máy nước Yên Lạc (11.672.368.775 VND) và khoản phải trả khác dài hạn tương ứng. Công ty cũng chưa ghi nhận chi phí khấu hao của nhà máy này.'),
('VPW_2016_consolidated', 'VPW', 2016, 'consolidated', 'Công ty TNHH Kiểm toán và Định giá Việt Nam', 'qualified', 0, NULL),
('VPS_2025_consolidated', 'VPS', 2025, 'consolidated', 'AASC', 'unqualified', 0, NULL),
('VPW_2018_consolidated', 'VPW', 2018, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
('VPS_2024_parent', 'VPS', 2024, 'parent', 'Công ty TNHH Kiểm toán AASC', 'unqualified', 1, 'Công ty Cổ phần Thuốc sát trùng Việt Nam khởi kiện Nhà đầu tư MosFly International SDN.BHD liên quan đến Công ty liên kết Công ty TNHH Mosfly Việt Nam Industries (MVI) đang tạm ngừng hoạt động. Bản án số 32/2024/KDTM-PT ngày 12/06/2024 của Tòa án nhân dân cấp cao tại TP. Hồ Chí Minh không chấp nhận một phần yêu cầu khởi kiện.'),
('VPS_2025_parent', 'VPS', 2025, 'parent', 'AASC Auditing Firm', 'unqualified', 0, NULL),
