INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VPS_2022_consolidated', 'VPS', 2022, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VPS_2023_parent', 'VPS', 2023, 'parent', 'AASC Auditing Firm', 'unqualified', 0, NULL),
('VPS_2022_parent', 'VPS', 2022, 'parent', 'AASC Auditing Firm', 'unqualified', 0, NULL),
('VPS_2021_consolidated', 'VPS', 2021, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Tại Công ty TNHH Mosfly Việt Nam Industries (MVI), kể từ thời điểm 31/03/2021, nợ phải trả ngắn hạn vượt quá tài sản ngắn hạn; Phần lớn các khoản phải trả của MVI đã quá hạn thanh toán và chưa có nguồn để hoàn trả; Nhà đầu tư Mosfly International SDN. BHD. (MISB) đã thu hồi lại thương hiệu Mosfly. Đồng thời, trong năm, MVI còn đang giải quyết nhiều đơn khởi kiện của các nhà cung cấp và người lao động.'),
('VPS_2021_parent', 'VPS', 2021, 'parent', 'Công ty TNHH Hằng Kiểm toán AASC', 'unqualified', 1, 'Tại Công ty TNHH Mosfly Việt Nam Industries (MVI), kể từ thời điểm 31/03/2021, nợ phải trả ngắn hạn vượt quá tài sản ngắn hạn; Phần lớn các khoản phải trả của MVI đã quá hạn thanh toán và chưa có nguồn để hoàn trả; Nhà đầu tư Mosfly International SDN. BHD. (MISB) đã thu hồi lại thương hiệu Mosfly. Đồng thời, trong năm, MVI còn đang giải quyết nhiều đơn khởi kiện của các nhà cung cấp và người lao động. Những sự kiện trên cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của MVI.'),
('VPS_2019_consolidated', 'VPS', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Công ty TNHH Sản xuất Nông dược Vi sinh Viguato (công ty con) có nguy cơ không hoạt động liên tục do Giấy chứng nhận đăng ký đầu tư hết hạn ngày 31/12/2019, phải di dời đến Khu công nghiệp tỉnh Sóc Trăng, giảm lao động từ 41 xuống 13 người, và chưa có kế hoạch sản xuất kinh doanh cụ thể. Báo cáo tài chính vẫn được hợp nhất dựa trên giả định hoạt động liên tục.'),
